import { useState, useEffect } from "react";
import axios from "axios";

function WelcomeOrphanage() {

  const [showForm, setShowForm] = useState(false);
  const [needs, setNeeds] = useState([]);

  const [form, setForm] = useState({
    title: "",
    description: "",
    category: "",
    targetAmount: "",
    deadline: ""
  });

  // FETCH EXISTING POSTS
  useEffect(() => {
    fetchNeeds();
  }, []);

  const fetchNeeds = async () => {
    const res = await axios.get("http://localhost:5000/api/needs/orphanage");
    setNeeds(res.data);
  };

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // POST NEED
  const postNeed = async () => {

    if (form.description.length > 500) {
      return alert("Description max 500 characters");
    }

    axios.post("http://localhost:5000/api/needs/create", {
  login: userEmailOrPhone,   // IMPORTANT
  title,
  description,
  category,
  targetAmount,
  deadline
});

    alert(res.data.message);

    setShowForm(false);
    fetchNeeds();
  };

  return (
    <div>

      <h1>Orphanage Dashboard</h1>

      {/* POST BUTTON */}
      <button onClick={() => setShowForm(true)}>
        Post a Need
      </button>

      {/* FORM */}
      {showForm && (
        <div style={{ border: "1px solid black", padding: 10 }}>

          <input
            name="title"
            placeholder="Need Title"
            onChange={handleChange}
          />

          <textarea
            name="description"
            placeholder="Description (max 500 chars)"
            maxLength={500}
            onChange={handleChange}
          />

          <input
            name="category"
            placeholder="Category"
            onChange={handleChange}
          />

          <input
            name="targetAmount"
            placeholder="Target Amount"
            onChange={handleChange}
          />

          <input
            type="date"
            name="deadline"
            onChange={handleChange}
          />

          <button onClick={() => setShowForm(false)}>
            Cancel
          </button>

          <button onClick={postNeed}>
            Post
          </button>

        </div>
      )}

      {/* DISPLAY POSTS */}
      <h2>Your Posted Needs</h2>

      {needs.map((n, i) => (
        <div key={i} style={{ border: "1px solid gray", margin: 10, padding: 10 }}>

          <h3>{n.title}</h3>
          <p>{n.description}</p>
          <p>Category: {n.category}</p>
          <p>Target: ₹{n.targetAmount}</p>
          <p>Deadline: {n.deadline}</p>

        </div>
      ))}

    </div>
  );
}

export default WelcomeOrphanage;
